// ── DOTS ─────────────────────────────────────────────────────────────────────

function dotR(n) {
  return n>80?5 : n>60?6 : n>40?7 : n>20?9 : n>10?12 : n>5?15 : 19;
}

function scatterDots(count, W=300, H=300) {
  if (!count) return [];
  const r = dotR(count);
  if (count > 35) {
    const cols = Math.ceil(Math.sqrt(count*(W/H)));
    const rows = Math.ceil(count/cols);
    const cW=W/cols, cH=H/rows, pts=[];
    let n=0;
    for (let row=0; row<rows && n<count; row++)
      for (let col=0; col<cols && n<count; col++) {
        pts.push({
          x: Math.max(r+2, Math.min(W-r-2, (col+.5)*cW + (Math.random()-.5)*cW*.55)),
          y: Math.max(r+2, Math.min(H-r-2, (row+.5)*cH + (Math.random()-.5)*cH*.55)),
        });
        n++;
      }
    return pts;
  }
  const minD=r*2.7, margin=r+8, placed=[];
  let att=0;
  while (placed.length<count && att<count*400) {
    const x=margin+Math.random()*(W-margin*2), y=margin+Math.random()*(H-margin*2);
    if (!placed.some(p=>Math.hypot(p.x-x,p.y-y)<minD)) placed.push({x,y});
    att++;
  }
  return placed;
}

function ScatteredDots({ count, size=300 }) {
  const pts = useMemo(()=>scatterDots(count,size,size),[count]); // eslint-disable-line
  const r   = dotR(count);
  return (
    <svg viewBox={`0 0 ${size} ${size}`} style={{width:`min(${size}px,85vw)`,height:`min(${size}px,85vw)`}}>
      {pts.map((p,i)=><circle key={i} cx={p.x} cy={p.y} r={r} fill={RED} opacity=".92"/>)}
    </svg>
  );
}

function MiniDots({ count, size=100 }) {
  const pts = useMemo(()=>scatterDots(count,size,size),[count]); // eslint-disable-line
  const r   = Math.max(3,dotR(count)*.7);
  return (
    <svg viewBox={`0 0 ${size} ${size}`} style={{width:size,height:size}}>
      {pts.map((p,i)=><circle key={i} cx={p.x} cy={p.y} r={r} fill={RED}/>)}
    </svg>
  );
}

// ── EQUATIONS ─────────────────────────────────────────────────────────────────

function genEquations(stage) {
  const isDots=stage==="eq-dots", mx=isDots?9:20, mm=isDots?5:10;
  const c=[];
  for (let a=1;a<=mx;a++) for (let b=1;b<=mx;b++) if(!isDots||a+b<=18) c.push({op:"+",a,b,result:a+b});
  for (let a=2;a<=mx+5;a++) for (let b=1;b<a;b++) c.push({op:"−",a,b,result:a-b});
  for (let a=1;a<=mm;a++) for (let b=1;b<=mm;b++) c.push({op:"×",a,b,result:a*b});
  for (let a=1;a<=mm;a++) for (let b=1;b<=mm;b++) c.push({op:"÷",a:a*b,b,result:a});
  return shuffle(c);
}

function getMathCards(stage) {
  if (stage==="dots"||stage==="numerals")
    return shuffle(Array.from({length:100},(_,i)=>({n:i+1})));
  return genEquations(stage);
}

// ── PHOTO DISPLAY ────────────────────────────────────────────────────────────
// Attempts external image sources with a timeout. If they don't load in time
// (e.g., blocked by sandbox), falls back to a large emoji "photo" treatment.

function PhotoDisplay({ word, emoji, seed, style }) {
  const [srcIdx, setSrcIdx] = useState(0);
  const [loaded, setLoaded] = useState(false);
  const [giveUp, setGiveUp] = useState(false);

  useEffect(()=>{
    setSrcIdx(0); setLoaded(false); setGiveUp(false);
    const timer = setTimeout(() => { if (!loaded) setGiveUp(true); }, 3500);
    return () => clearTimeout(timer);
  }, [word, seed]); // eslint-disable-line

  const w = encodeURIComponent(word||"");
  const sources = [
    `https://loremflickr.com/400/400/${w}?lock=${seed||1}`,
    `https://source.unsplash.com/400x400/?${w}`,
    `https://picsum.photos/seed/${w}${seed||0}/400/400`,
  ];

  // All sources failed or timed out → large emoji treatment
  if (giveUp || srcIdx >= sources.length) {
    return (
      <div style={{
        ...style,
        background: "linear-gradient(135deg, #FFF0F1 0%, #FFE4E6 100%)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        fontSize: 180,
        lineHeight: 1,
      }}>
        {emoji || "📸"}
      </div>
    );
  }

  return (
    <>
      {!loaded && (
        <div style={{...style, display:"flex", alignItems:"center", justifyContent:"center", background:"#FAFAFA"}}>
          <Spinner/>
        </div>
      )}
      <img
        key={`${word}-${srcIdx}`}
        src={sources[srcIdx]}
        alt={word}
        onLoad={()=>setLoaded(true)}
        onError={()=>{ setLoaded(false); setSrcIdx(i=>i+1); }}
        style={{...style, display: loaded ? "block" : "none"}}
      />
    </>
  );
}

