async function translateWords(words, lang) {
  // Try dictionary first for every word
  const missing = [];
  const translated = words.map(w => {
    const hit = CORE_TRANSLATIONS[w.word?.toLowerCase()]?.[lang];
    if (hit) return { ...w, word: hit, original: w.word };
    missing.push(w);
    return { ...w, original: w.word };
  });

  // If dictionary covered everything, return immediately — no network call!
  if (!missing.length) return translated;

  // If dictionary doesn't cover a word, it stays in English — no API needed
  return translated;
}

async function fetchDailyWords(dk) {
  // Pull from core vocabulary that has reliable translations.
  // Use the date as a seed to rotate through a larger pool.
  const pool = Object.keys(CORE_TRANSLATIONS).map(w => {
    const emojis = {
      mama:"👩",dada:"👨",baby:"👶",ball:"⚽",cat:"🐱",dog:"🐶",sun:"☀️",moon:"🌙",
      tree:"🌳",fish:"🐟",bird:"🐦",apple:"🍎",flower:"🌸",water:"💧",milk:"🥛",
      book:"📖",banana:"🍌",car:"🚗",house:"🏠",star:"⭐"
    };
    return { word: w, emoji: emojis[w] || "✨" };
  });

  // Deterministic daily rotation
  const seed = dk.split("-").reduce((a,s)=>a+parseInt(s),0);
  const rotated = [...pool.slice(seed % pool.length), ...pool.slice(0, seed % pool.length)];
  return rotated.slice(0, 15);
}

