            <div style={{width:28,height:28,borderRadius:"50%",background:selected===s.id?RED:"#f0f0f0",color:selected===s.id?"#fff":"#999",display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"'Fredoka One',cursive",fontSize:13,flexShrink:0}}>{i+1}</div>
            <div>
