// ── SESSION HEADER ────────────────────────────────────────────────────────────

function SessionHeader({ onBack, index, total, streak, autoPlay, onAutoPlay, extraDots }) {
  return (
    <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"14px 18px",borderBottom:"1px solid #f5f5f5"}}>
      <button onClick={onBack} style={{background:"#f5f5f5",border:"none",borderRadius:50,width:38,height:38,fontSize:17,cursor:"pointer",color:"#555",display:"flex",alignItems:"center",justifyContent:"center"}}>←</button>
      <div style={{display:"flex",alignItems:"center",gap:8}}>
        <span style={{fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:13,color:"#ccc"}}>{index+1}/{total} · 🔥{streak}</span>
        {extraDots}
      </div>
      {onAutoPlay
        ? <button onClick={onAutoPlay} style={{background:autoPlay?RED:"#f5f5f5",border:"none",borderRadius:18,padding:"6px 14px",cursor:"pointer",color:autoPlay?"#fff":"#666",fontSize:13,fontFamily:"Nunito,sans-serif",fontWeight:800,transition:"all .2s"}}>
            {autoPlay?"⏸ Auto":"▶ Auto"}
          </button>
        : <div style={{width:60}}/>
      }
    </div>
  );
}

function ProgressBar({ index, total }) {
  return (
    <div style={{height:4,background:"#f5f5f5",margin:"0 18px 22px"}}>
      <div style={{height:"100%",background:RED,borderRadius:2,width:`${((index+1)/Math.max(total,1))*100}%`,transition:"width .4s ease"}}/>
    </div>
  );
}

// ── READING SESSION (3-frame Doman: word → photo → word → next) ───────────────

function ReadingSession({ words, language, onBack }) {
  const [cards, setCards]     = useState([]);
  const [translating, setTranslating] = useState(false);
  const [transError, setTransError]   = useState(null);
  const [idx, setIdx]         = useState(0);
  const [frame, setFrame]     = useState(0); // 0=word, 1=photo, 2=word-again
  const [visible, setVisible] = useState(true);
  const [autoPlay, setAutoPlay] = useState(false);
  const [streak, setStreak]   = useState(0);

  useEffect(()=>{
    setIdx(0); setFrame(0); setStreak(0); setTransError(null);
    if (language==="English") { setCards(shuffle(words)); return; }
    const run = async ()=>{
      setTranslating(true);
      try {
        const t = await translateWords(words, language);
        setCards(shuffle(t));
      } catch(e) {
        setTransError(`${language}: ${e.message}`);
        setCards(shuffle(words));
      }
      setTranslating(false);
    };
    run();
  },[language, words]);

  const advance = useCallback(()=>{
    setVisible(false);
    setTimeout(()=>{
      if (frame < 2) {
        setFrame(f => f + 1);
      } else {
        setFrame(0);
        setIdx(i => (i + 1) % Math.max(cards.length, 1));
        setStreak(s => s + 1);
      }
      setVisible(true);
    }, 230);
  },[frame, cards.length]);

  useEffect(()=>{
    if (!autoPlay||translating) return;
    const dur = frame === 1 ? 2600 : 1300; // photo held longer than words
    const t = setTimeout(advance, dur);
    return ()=>clearTimeout(t);
  },[autoPlay,frame,idx,advance,translating]);

  if (translating) return <LoadingScreen message={`Translating to ${language}…`}/>;

  const card    = cards[idx]||{};
  const engWord = card.original||card.word||"";
  const wordLen = card.word?.length||0;
  const wordSize = wordLen>10?50:wordLen>7?64:82;

  const frameDots = (
    <div style={{display:"flex",gap:5}}>
      {[0,1,2].map(f=>(
        <div key={f} style={{width:7,height:7,borderRadius:"50%",background:frame===f?RED:"#ddd",transition:"background .3s"}}/>
      ))}
    </div>
  );

  const WordDisplay = () => (
    <>
      <div style={{fontSize:wordSize,fontFamily:"'Fredoka One',cursive",color:RED,textAlign:"center",lineHeight:1.1,letterSpacing:1}}>
        {card.word}
      </div>
      {language!=="English"&&card.original&&(
        <div style={{marginTop:10,fontFamily:"Nunito,sans-serif",fontWeight:700,color:"#ddd",fontSize:13}}>en: {card.original}</div>
      )}
    </>
  );

  return (
    <div style={{minHeight:"100vh",background:"#fff",display:"flex",flexDirection:"column"}}>
      <SessionHeader onBack={onBack} index={idx} total={cards.length} streak={streak} autoPlay={autoPlay} onAutoPlay={()=>setAutoPlay(a=>!a)} extraDots={frameDots}/>
      {transError && <div style={{background:"#FFF0F1",padding:"6px 14px",fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:11,color:RED,textAlign:"center",wordBreak:"break-word"}}>{transError}</div>}

      <div onClick={advance}
        style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:24,cursor:"pointer",opacity:visible?1:0,transform:visible?"scale(1)":"scale(.96)",transition:"opacity .22s, transform .22s"}}>

        {(frame===0 || frame===2) && <WordDisplay/>}

        {frame===1 && (
          <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:18,width:"100%",maxWidth:340}}>
            <PhotoDisplay
              word={engWord}
              emoji={card.emoji}
              seed={idx}
              style={{
                width:"min(300px,82vw)",
                height:"min(300px,82vw)",
                objectFit:"cover",
                borderRadius:22,
                boxShadow:"0 8px 32px rgba(0,0,0,.14)"
              }}
            />
          </div>
        )}

        <p style={{marginTop:30,color:"#e8e8e8",fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:12}}>
          {frame===0 ? "tap to see photo →" : frame===1 ? "tap to see word again →" : "tap for next word →"}
        </p>
      </div>
      <ProgressBar index={idx} total={cards.length}/>
    </div>
  );
}

// ── MATH SESSION ──────────────────────────────────────────────────────────────

function MathSession({ mathStage, onBack }) {
  const [cards]   = useState(()=>getMathCards(mathStage));
  const [idx, setIdx]     = useState(0);
  const [visible, setVisible] = useState(true);
  const [autoPlay, setAutoPlay] = useState(false);
  const [streak, setStreak]   = useState(0);
  const [revealed, setRevealed] = useState(false);
  const isEq = mathStage.startsWith("eq");

  useEffect(()=>setRevealed(false),[idx]);

  const advance = useCallback(()=>{
    setVisible(false);
    setTimeout(()=>{ setIdx(i=>(i+1)%cards.length); setStreak(s=>s+1); setVisible(true); }, 250);
  },[cards.length]);

  useEffect(()=>{
    if (!autoPlay||isEq) return;
    const t=setTimeout(advance,1800); return ()=>clearTimeout(t);
  },[autoPlay,idx,advance,isEq]);

  const card=cards[idx]||{};
  const showDots=mathStage==="eq-dots"||mathStage==="eq-both";
  const showNums=mathStage==="eq-numerals"||mathStage==="eq-both";
  const bigN={fontSize:showDots?22:50,fontFamily:"'Fredoka One',cursive",color:RED,textAlign:"center",lineHeight:1};
  const opSty={fontSize:showDots?28:52,fontFamily:"'Fredoka One',cursive",color:"#222",lineHeight:1,padding:"0 4px"};

  const Qty=({n})=>(
    <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:4}}>
      {showDots&&<MiniDots count={n} size={Math.min(95,Math.max(55,95-n))}/>}
      {showNums&&<div style={bigN}>{n}</div>}
    </div>
  );

  return (
    <div style={{minHeight:"100vh",background:"#fff",display:"flex",flexDirection:"column"}}>
      <SessionHeader onBack={onBack} index={idx} total={cards.length} streak={streak}
        autoPlay={autoPlay} onAutoPlay={isEq?null:()=>setAutoPlay(a=>!a)}/>

      <div onClick={isEq?undefined:advance}
        style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:24,cursor:isEq?"default":"pointer",opacity:visible?1:0,transform:visible?"scale(1)":"scale(.96)",transition:"opacity .22s, transform .22s"}}>

        {mathStage==="dots" && <ScatteredDots count={card.n} size={300}/>}
        {mathStage==="numerals" && <div style={{fontSize:120,fontFamily:"'Fredoka One',cursive",color:RED,lineHeight:1}}>{card.n}</div>}

        {isEq && (
          <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:10,width:"100%"}}>
            <div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:showDots?6:14,flexWrap:"wrap"}}>
              <Qty n={card.a}/><div style={opSty}>{card.op}</div><Qty n={card.b}/>
            </div>
            <div style={opSty}>=</div>
            {revealed
              ? <>
                  <Qty n={card.result}/>
                  <button onClick={advance} style={{marginTop:14,background:"#f5f5f5",border:"none",borderRadius:18,padding:"8px 20px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:13,color:"#666"}}>next →</button>
                </>
              : <button onClick={()=>setRevealed(true)}
                  style={{background:"#FFF0F1",border:`2px dashed ${RED}`,borderRadius:14,padding:"11px 26px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:RED}}>
                  tap to reveal ✦
                </button>
            }
          </div>
        )}

        {!isEq && <p style={{marginTop:28,color:"#e0e0e0",fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:12}}>tap to advance →</p>}
      </div>
      <ProgressBar index={idx} total={cards.length}/>
    </div>
  );
}

// ── ENCYCLOPEDIA SESSION ──────────────────────────────────────────────────────

function EncyclopediaSession({ knowledge, onBack }) {
  const cards = useMemo(()=>shuffle(knowledge),[knowledge]);
  const [idx, setIdx]     = useState(0);
  const [visible, setVisible] = useState(true);
  const [autoPlay, setAutoPlay] = useState(false);
  const [streak, setStreak]   = useState(0);

  const advance = useCallback(()=>{
    setVisible(false);
    setTimeout(()=>{ setIdx(i=>(i+1)%cards.length); setStreak(s=>s+1); setVisible(true); }, 250);
  },[cards.length]);

  useEffect(()=>{
    if (!autoPlay) return;
    const t=setTimeout(advance,3500); return ()=>clearTimeout(t);
  },[autoPlay,idx,advance]);

  const card=cards[idx]||{};
  return (
    <div style={{minHeight:"100vh",background:"#fff",display:"flex",flexDirection:"column"}}>
      <SessionHeader onBack={onBack} index={idx} total={cards.length} streak={streak} autoPlay={autoPlay} onAutoPlay={()=>setAutoPlay(a=>!a)}/>

      <div onClick={advance}
        style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:24,cursor:"pointer",opacity:visible?1:0,transform:visible?"scale(1)":"scale(.96)",transition:"opacity .22s, transform .22s"}}>
        <div style={{fontSize:68,marginBottom:12}}>{card.emoji}</div>
        <div style={{fontSize:32,fontFamily:"'Fredoka One',cursive",color:RED,textAlign:"center",marginBottom:16}}>{card.title}</div>
        <div style={{background:"#FFF0F1",borderRadius:18,padding:"14px 24px",maxWidth:300,textAlign:"center",color:"#555",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:15,lineHeight:1.5}}>{card.fact}</div>
        <p style={{marginTop:32,color:"#e8e8e8",fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:12}}>tap to advance →</p>
      </div>
      <ProgressBar index={idx} total={cards.length}/>
    </div>
  );
}

// ── APP ROOT ──────────────────────────────────────────────────────────────────

export default function App() {
  const [mode, setMode]               = useState(null);
  const [language, setLanguage]       = useState("English");
  const [mathStage, setMathStage]     = useState("dots");
  const [showLang, setShowLang]       = useState(false);
  const [showMath, setShowMath]       = useState(false);
  const [dailyWords, setDailyWords]   = useState([]);
  const [dailyKnow, setDailyKnow]     = useState([]);
  const [initializing, setInit]       = useState(true);

  useEffect(()=>{
    const run = async ()=>{
      const dk = todayKey();
      let words=null, know=null;
      try { const r=localStorage.getItem(`lb-w-${dk}`); words=r?JSON.parse(r):null; } catch {}
      try { const r=localStorage.getItem(`lb-k-${dk}`); know =r?JSON.parse(r):null; } catch {}
      if (!words) { try { words=await fetchDailyWords(dk); localStorage.setItem(`lb-w-${dk}`,JSON.stringify(words)); } catch { words=FALLBACK_WORDS; } }
      if (!know)  { try { know=await fetchDailyKnowledge(dk); localStorage.setItem(`lb-k-${dk}`,JSON.stringify(know)); } catch { know=FALLBACK_KNOW; } }
      setDailyWords(words); setDailyKnow(know); setInit(false);
    };
    run();
    try { const r=localStorage.getItem("lb-math"); if(r) setMathStage(r); } catch {}
  },[]);

  const handleMath = s=>{ setMathStage(s); try { localStorage.setItem("lb-math",s); } catch {} };

  if (initializing) return <LoadingScreen message="Preparing today's lessons…"/>;

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Fredoka+One&family=Nunito:wght@700;800;900&display=swap');
        *{box-sizing:border-box;margin:0;padding:0;}body{margin:0;background:#fff;}
        button:focus{outline:none;}@keyframes spin{to{transform:rotate(360deg)}}
      `}</style>
      {mode===null       && <HomeScreen onSelect={setMode} language={language} mathStage={mathStage} onLang={()=>setShowLang(true)} onMath={()=>setShowMath(true)}/>}
      {mode==="reading"  && <ReadingSession words={dailyWords} language={language} onBack={()=>setMode(null)}/>}
      {mode==="math"     && <MathSession mathStage={mathStage} onBack={()=>setMode(null)}/>}
      {mode==="encyclopedia" && <EncyclopediaSession knowledge={dailyKnow} onBack={()=>setMode(null)}/>}
      {showLang && <LanguagePicker selected={language} onSelect={setLanguage} onClose={()=>setShowLang(false)}/>}
      {showMath && <MathStagePicker selected={mathStage} onSelect={handleMath} onClose={()=>setShowMath(false)}/>}
    </>
  );
}
